const items = $input.all();
const d = items[0]?.json || {};
const peers = items.slice(1).map(i => i.json).filter(p => p.peer_ticker);

let peerInfo = '';
if (peers.length > 0) {
  peerInfo = '\n\nIndustry Peers (from Neo4j graph):';
  for (const p of peers) {
    peerInfo += `\n- ${p.peer_name} (${p.peer_ticker})${p.on_watchlists?.length ? ' [on: ' + p.on_watchlists.join(', ') + ']' : ''}`;
  }
}

return [{json:{ticker:d.ticker,context:`Dividend analysis:\nTicker: ${d.ticker} (${d.company_name})\nSector: ${d.sector} | Industry: ${d.industry} | Cap: $${(d.market_cap/1e9).toFixed(1)}B\nYield: ${(d.dividend_yield*100).toFixed(2)}% | Payout: ${(d.payout_ratio*100).toFixed(1)}%\nFCF: $${(d.free_cash_flow/1e6).toFixed(0)}M | D/E: ${d.debt_to_equity}\nROE: ${(d.roe*100).toFixed(1)}% | Margin: ${(d.net_margin*100).toFixed(1)}%${peerInfo}\nDate: ${new Date().toISOString().split('T')[0]}\n\nCompare yield and safety vs industry peers. Evaluate safety, growth, income recommendation.`}}];
